import './App.css';
import React, {useEffect, useState} from "react";
import Axios from "axios";
import "./styles.css";
import 'react-edit-text/dist/index.css';

function App() {
    const [listofArtworks, setListOfArtworks] = useState([]);
    const [artwork, setArtwork] = useState("");
    const [artist, setArtist] = useState("");
    const [movement, setMovement] = useState("");
    const [year, setYear] = useState(0);
    const [color, setColor] = useState("");

    async function fetchData() {
        const response = await Axios.get(process.env.REACT_APP_HOST_LINK + "/getArtworks");
        setListOfArtworks(response.data)
    }

    useEffect(() => {
        fetchData();
    }, []);


    const createArtwork = () => {
        Axios.post(process.env.REACT_APP_HOST_LINK + "/createBook", {
            artwork, artist, movement, year, color
        }).then(() => {
            fetchData();
        });
    };


    const deleteBook = (id) => {
        Axios.delete(`http://localhost:3000/deleteBook/${id}`)
            .then((id) => {
                console.log(id);
                fetchData();
            });
    };

    const clearBooks = () => {
        Axios.delete("http://localhost:3000/clearBooks/")
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };

    const updateBook = (id, newBookAuthor, newBookTitle, newBookYear, newBookColor) => {
        newBookAuthor = newBookAuthor || undefined;
        newBookTitle = newBookTitle || undefined;
        Axios.put("http://localhost:3000/updateBook/", {
            id: id, author: newBookAuthor, title: newBookTitle, year: parseInt(newBookYear), color: newBookColor
        })
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };



    return (<div className="App">
        <div className="booksDisplay">
            {listOfBooks.map((book) => {

                return (<div className="cssBooksParent">
                    <h1 className="cssTitle"
                        style={{backgroundColor: book.color}}> {book.title}</h1>
                    <h1 className="cssAuthor"
                        style={{backgroundColor: book.color}}>{book.author}</h1>
                    <h1 className="cssYear"
                        style={{backgroundColor: book.color}}>{book.year}</h1>
                    <button onClick={() => {
                        const newBookTitle = prompt('Input text to change the title.');
                        const newBookAuthor = prompt('Input text to change the author.');
                        const newBookYear = prompt('Input a number to change the year.');
                        if (newBookAuthor || newBookTitle || newBookYear) {
                            updateBook(book._id, newBookAuthor, newBookTitle, newBookYear)
                        } else {
                            alert("Please enter something.")
                        }
                    }}> Update
                    </button>
                    <button onClick={() => {
                        if (window.confirm('Delete?')) {
                            deleteBook(book._id)
                        }
                    }}> Delete
                    </button>
                </div>)

            })}

        </div>
        <div>
            <input
                type="text"
                placeholder="Title"
                onChange={(event) => {
                    setTitle(event.target.value);
                }}
            />
            <input
                type="text"
                placeholder="Author"
                onChange={(event) => {
                    setAuthor(event.target.value);
                }}
            />
            <input
                type="number"
                placeholder="Year"
                onChange={(event) => {
                    setYear(event.target.value);
                }}
            />
            <input
                type="color"
                placeholder="Hex Color"
                onChange={(event) => {
                    setColor(event.target.value);
                }}
            />
            <button onClick={createBook}> Create Book</button>
            <button onClick={() => {
                if (window.confirm('Clear?')) {
                    clearBooks();
                }
            }}> Clear Books
            </button>
        </div>
    </div>);

}

export default App;
